public int distinctAverages(int[] nums) {
    Set<Double> averages = new HashSet<>();
    Arrays.sort(nums);
    int n = nums.length;
    for (int i = 0; i < n / 2; i++) {
        averages.add((nums[i] + nums[n - 1 - i]) / 2.0);
    }
    return averages.size();
}
```

